#!/usr/bin/env python3
"""
Test script for Drug-Drug Interaction Model integration
Validates model loading and prediction with sample data
"""

import numpy as np
import torch
import sys
import json
from pathlib import Path

# Add project root to path
sys.path.insert(0, str(Path(__file__).parent))

from model_drug_detection import ModelManager

def test_model_loading():
    """Test model loading"""
    print("\n" + "="*60)
    print("TEST 1: Model Loading")
    print("="*60)
    
    model_path = Path(__file__).parent / 'best_model.pth'
    print(f"Loading model from: {model_path}")
    
    try:
        model_manager = ModelManager(model_path)
        print("✓ Model loaded successfully")
        print(f"  Device: {model_manager.device}")
        print(f"  Input size: {model_manager.input_size}")
        print(f"  Class names: {model_manager.class_names}")
        return model_manager
    except Exception as e:
        print(f"✗ Failed to load model: {e}")
        return None

